	// Without ticker registration, the slug becomes a non-entity token.
	want := "look slug-thing-foo-456 up"
	if got.NonEntityNormalized != want {
		t.Errorf("NonEntityNormalized = %q, want %q", got.NonEntityNormalized, want)
	}
